<script>
  import Select from "svelte-select";
  import { onMount } from "svelte";
  import { COUNTRY_CODES } from "./utils/constants/countryCodes.js";
  import { REFERRALS } from "./utils/constants/referrals.js";
  import Captcha from "./components/Captcha.svelte";
  import Error from "./components/Error.svelte";
  import Loader from "./components/Loader.svelte";
  import axios from "axios";
  import mainEnv from "./env/main.json";

  export let options = {};
  export let token;
  export let api;

  export let email;
  export let password;
  export let firstName;
  export let lastName;
  export let countryCode;
  export let phone;
  export let localOffice;
  export let terms;
  export let loadingElements = {};
  export let placeholders = {
    alignment: "Local Office (City)",
  };
  export let countryCodes = COUNTRY_CODES;

  export let errorMessage;
  export let showValidationError = false;

  let currentCountry;
  let grecaptchaToken;
  let allAlignments = [];
  let selectedAlignments = [];
  export let country = {};
  let env = {};
  export const documentHeight = window.innerHeight;
  export const documentWidth = window.innerWidth;

  export let passwordRegex = "(?=.*\\d)(?=.*[a-z])(?=.*[A-Z]).{8,}";
  export let referrals = REFERRALS.map((ref) => ({ label: ref, value: ref }));
  export let referral;

  onMount(() => {
    setDefaults();
    if (!options.showLogin) {
      fetchAllAlignments();
    }
  });

  function setDefaults() {
    const getDefaultIfNullish = (value, defaultValue) => {
      return value === null || value === undefined ? defaultValue : value;
    };

    options = {
      // button_color: '#1781f0',
      registerButtonText: options.registerButtonText || "Get Started",
      loginButtonText: options.loginButtonText || "Login",
      defaultReferral: options.defaultReferral,
      afterLoginRedirectTo: options.afterLoginRedirectTo || "",
      title: getDefaultIfNullish(options.title, "Login/Register with AIESEC"),
      // It is important to only check for null and undefined here as users should be able to disable the title
      loginFormTitle: getDefaultIfNullish(options.loginFormTitle, "Login"),
      regsiterFormTitle: getDefaultIfNullish(
        options.registerFormTitle,
        "Register"
      ),
      showLogin: getDefaultIfNullish(options.showLogin, true),
      utm: options.utm || null,
      customMeta: options.customMeta || null,
      profileAttributes: options.profileAttributes || null,
      disableFormToggle: options.disableFormToggle || false,
      useModalLayout: getDefaultIfNullish(options.useModalLayout, true),
      allowPhoneCommunication: options.allowPhoneCommunication || false,
    };
    token =
      token ||
      "e8f212e937b3ad94da3901c93172b95a19b118e749d1234b4466e120b58bfbaadb2e4a9ff9eae08e9199f0f9b07b9541ea21216baa817d353ec7d846e25b1473";
    api = api || "production";
  }

  if (api === "staging") {
    env = {...mainEnv.staging};
  } else {
    env = {...mainEnv.prod};
  }

  const getCountry = async () => {
    const res = await axios.get(`${env.authUrl}/registrations/get_country`);
    currentCountry = res.data;
    currentCountry = currentCountry.name.toString().replace("+", " ");
    if (currentCountry == null || currentCountry == "") {
      currentCountry = "India";
    }
    country = allAlignments.find((i) => i.name === currentCountry);
    setSelectedAlignments();
  };

  const fetchAllAlignments = async () => {
    loadingElements.alignments = true;
    const res = await axios.get(
      `${env.apiUrl}/v2/lists/mcs_alignments.json?mc_id[]=495&mc_id[]=537`
    );
    loadingElements.alignments = false;
    res.data.forEach((i) => {
      i.originalLabel = i.label;
      i.label = i.name;
      i.value = i.id;
    });
    allAlignments = res.data;
    getCountry();
  };

  const setSelectedAlignments = () => {
    if (country.originalLabel) {
      placeholders.alignment = country.originalLabel;
    } else {
      placeholders.alignment = "Local Office (City)";
    }
    selectedAlignments = country.alignments.map((i) => {
      return {
        label: i.value,
        value: i.id,
        alignment_id: i.alignment_id,
      };
    });
  };

  const checkCaptcha = (event) => {
    event.preventDefault();

    grecaptcha.execute();
  };

  const onCaptchaSuccess = (res) => {
    grecaptchaToken = grecaptcha.getResponse();
    if (options.showLogin) {
      login();
    } else {
      signup();
    }
  };

  const login = async (e) => {
    const data = {
      token: token,
      email: email,
      password: password,
      grecaptcha_token: grecaptchaToken,
      redirect_url: options.afterLoginRedirectTo,
    };
    find_or_create_and_login(data, "/plugin/sign_in");
  };

  const signup = async (e) => {
    if (!checkSignupValidations()) {
      grecaptcha.reset();
      return;
    }

    let data = {
      token,
      created_via: "plugin",
      email,
      password,
      first_name: firstName,
      last_name: lastName,
      country_code: countryCode.value,
      phone: phone,
      country: country.value,
      lc: localOffice.value,
      referral_type: referral ? referral.value : options.defaultReferral,
      alignment_id: localOffice.alignment_id,
      grecaptcha_token: grecaptchaToken,
      redirect_url: options.afterLoginRedirectTo,
      allow_phone_communication: options.allowPhoneCommunication ? "1" : "0",
    };

    if (options.utm) {
      data.utm_source = options.utm.utm_source;
      data.utm_medium = options.utm.utm_medium;
      data.utm_campaign = options.utm.utm_campaign;
      data.utm_term = options.utm.utm_term;
      data.utm_content = options.utm.utm_content;
    }
    if (options.customMeta) {
      data.custom_meta = options.customMeta;
    }
    if (options.profileAttributes) {
      data.profile_attributes = options.profileAttributes;
    }
    find_or_create_and_login(data, "/plugin/register");
  };

  const find_or_create_and_login = (data, path) => {
    loadingElements.submit = true;
    axios.post(env.authUrl + path, data).then(
      (response) => {
        loadingElements.submit = false;
        if (response) {
          window.location.replace(`${response.data.redirect_url}`);
        }
      },
      (err) => {
        loadingElements.submit = false;
        console.log("error is: ", err);
        errorMessage = err.response.data.message;
        grecaptcha.reset();
      }
    );
  };

  const close = () => {
    const appEle = document.getElementById("app-embeddable-auth");
    appEle.parentNode.removeChild(appEle);
  };

  function toggleView(view, event) {
    errorMessage = null;
    if (event) {
      event.preventDefault();
    }
    options.showLogin = !(view === "signup");
    if (!options.showLogin) {
      if (!allAlignments || !allAlignments.length) {
        fetchAllAlignments();
      }
    }
  }

  function setSelectedCountryCode(event) {
    countryCode.label = `+${countryCode.value}`;
  }

  function showPasswordValidation(event) {
    if (firstName && lastName && email && password) {
      event.target.parentNode.reportValidity();
    }
  }

  function checkSignupValidations() {
    if (!countryCode || !countryCode.value) {
      showValidationError = true;
      return false;
    }
    if (!country || !country.value) {
      showValidationError = true;
      return false;
    }
    if (!localOffice || !localOffice.value || !localOffice.alignment_id) {
      showValidationError = true;
      return false;
    }
    return true;
  }
</script>

<main id="app-embeddable-auth">
  <div
    class="form-box-container popup"
    class:popup={options.useModalLayout === true}
  >
    <div id="aiesec_session_box" class="form-box">
      {#if options.useModalLayout === true}
        <div class="text-right">
          <button class="form-close-btn" on:click={close}> &#10005; </button>
        </div>
      {/if}
      <div class="form-wrapper">
        {#if options.title}
          <h2 id="title" class="form-heading">{options.title}</h2>
        {/if}
        {#if options.showLogin}
          <form id="login_box" on:submit={checkCaptcha}>
            {#if options.loginFormTitle}
              <h2 class="form-heading">{options.loginFormTitle}</h2>
            {/if}
            <input
              class="form-field"
              type="email"
              name="email"
              placeholder="Email"
              bind:value={email}
              required
            />
            <input
              class="form-field"
              type="password"
              name="password"
              placeholder="Password"
              bind:value={password}
              required
            />
            <Error {errorMessage} />
            <div class="form-captcha">
              <Captcha on:callback={onCaptchaSuccess} />
            </div>
            {#if !loadingElements.submit}
              <button type="submit" class="auth-btn" id="aiesec_submit_btn"
                >{options.loginButtonText || "Login"}</button
              >
            {:else}
              <Loader />
            {/if}
            {#if !options.disableFormToggle}
              <button
                on:click={(event) => toggleView("signup", event)}
                class="register-btn">Or Register</button
              >
            {/if}
          </form>
        {:else}
          <div id="signup_box">
            {#if loadingElements.alignments}
              <Loader />
            {:else}
              <form on:submit={checkCaptcha}>
                {#if options.regsiterFormTitle}
                  <h2 class="form-heading">{options.regsiterFormTitle}</h2>
                {/if}
                <input
                  class="form-field"
                  type="text"
                  name="first_name"
                  bind:value={firstName}
                  placeholder="First Name"
                  required
                />
                <input
                  class="form-field"
                  type="text"
                  name="last_name"
                  bind:value={lastName}
                  placeholder="Last Name"
                  required
                />
                <input
                  class="form-field"
                  type="email"
                  name="email"
                  bind:value={email}
                  placeholder="Email"
                  required
                />
                <input
                  class="form-field"
                  type="password"
                  name="password"
                  bind:value={password}
                  placeholder="Password"
                  required
                  title="Must contain at least one  number and one uppercase and lowercase letter, and at least 8 or more characters"
                  pattern={passwordRegex}
                />
                <div class="phone-selection">
                  <div
                    id="countryCodeEle"
                    class="auth-select countrycode-select"
                  >
                    <Select
                      bind:items={countryCodes}
                      bind:selectedValue={countryCode}
                      on:select={(event) => {
                        setSelectedCountryCode(event);
                      }}
                      isClearable={false}
                      placeholder="+91"
                    />
                  </div>
                  <input
                    class="form-field"
                    type="tel"
                    name="phone"
                    bind:value={phone}
                    placeholder="Phone Number"
                    required
                    title="Please enter a valid mobile number"
                    pattern="[^a-zA-Z]+"
                  />
                </div>
                {#if showValidationError && (!countryCode || !countryCode.value)}
                  <Error errorMessage={"Please select country code"} />
                {/if}
                <div class="terms-conditions">
                  <input
                    type="checkbox"
                    name="allow_phone_communication"
                    id="allow_phone_communication"
                    bind:checked={options.allowPhoneCommunication}
                  />
                  <label for="allow_phone_communication">
                    I agree to receiving calls or messages from AIESEC. We will not use your number for promotional purposes.
                  </label>
                </div>
                <div class="auth-select">
                  <Select
                    bind:items={allAlignments}
                    bind:selectedValue={country}
                    on:select={setSelectedAlignments}
                    isClearable={false}
                    placeholder="Select Country"
                  />
                  {#if showValidationError && (!country || !country.value)}
                    <Error errorMessage={"Please select a country"} />
                  {/if}
                </div>
                <div class="auth-select alignment-select">
                  <Select
                    bind:items={selectedAlignments}
                    bind:placeholder={placeholders.alignment}
                    bind:selectedValue={localOffice}
                    isClearable={false}
                  />
                  {#if showValidationError && (!localOffice || !localOffice.value)}
                    <Error errorMessage={"Please select a local office"} />
                  {/if}
                </div>
                {#if !options.defaultReferral}
                  <div class="auth-select alignment-select">
                    <Select
                      bind:items={referrals}
                      placeholder="Where did you first hear about us?"
                      bind:selectedValue={referral}
                      isClearable={false}
                    />
                  </div>
                {/if}
                <div class="terms-conditions">
                  <input
                    type="checkbox"
                    name="terms"
                    bind:value={terms}
                    required
                  />
                  <label for="terms"
                    >By signing up you accept our <a
                      href="https://aiesec.org/assets/documents/AIESEC_Privacy_Policy2022.pdf"
                      target="_blank">terms and conditions</a
                    ></label
                  >
                </div>
                <Error {errorMessage} />
                <div class="form-captcha">
                  <Captcha on:callback={onCaptchaSuccess} />
                </div>
                {#if !loadingElements.submit}
                  <button
                    class="auth-btn"
                    type="submit"
                    id="aiesec_submit_btn"
                    disabled={loadingElements.alignments}
                    >{options.registerButtonText || "Get Started"}</button
                  >
                {:else}
                  <Loader />
                {/if}
                {#if !options.disableFormToggle}
                  <button
                    on:click={(event) => toggleView("login", event)}
                    class="register-btn">Or Login</button
                  >
                {/if}
              </form>
            {/if}
          </div>
        {/if}
      </div>
    </div>
  </div>
</main>

